mapper.select:
SELECT '' AS INV_SQ , POHD.PO_NUM , PODT.PO_SQ , PODT.ITEM_CD , PODT.ITEM_DESC , PODT.ITEM_SPEC , PODT.MAKER_CD ,GETMKBRNAME(PODT.GATE_CD, PODT.BUYER_CD, 'MK', PODT.MAKER_CD) AS MAKER_NM , PODT.MAKER_PART_NO , PODT.PO_QT , PODT.UNIT_CD , PODT.DUE_DATE , PODT.PO_QT - (PODT.GR_QT, 0) - (SUM_IVDT.INV_QT, 0) AS UN_PO_QT -- 발주잔량(=발주수량 - 입고수량 - 작성중/검수요청 수량) , 0 AS IN_INV_QT , 0 AS OLD_INV_QT , PODT.INV_QT , PODT.UNIT_PRC , 0 AS INV_AMT , POHD.PO_CREATE_DATE , POHD.CTRL_USER_ID ,GETUSERNAME(POHD.GATE_CD, POHD.CTRL_USER_ID, #{ses.langCd}) AS CTRL_USER_NM ,GETUSERINFO(POHD.GATE_CD, POHD.CTRL_USER_ID, 'USER_TYPE') AS CTRL_USER_TYPE , POHD.INSPECT_USER_ID ,GETUSERNAME(POHD.GATE_CD, POHD.INSPECT_USER_ID, #{ses.langCd}) AS INSPECT_USER_NM ,GETUSERINFO(POHD.GATE_CD, POHD.INSPECT_USER_ID, 'USER_TYPE') AS INSPECT_USER_TYPE , 0 AS VAT_AMT , PODT.BUYER_CD , POHD.DEPT_CD , PODT.PR_BUYER_CD , PODT.PR_DEPT_CD FROM STOCPOHD POHD JOIN STOCPODT PODT ON (PODT.GATE_CD = POHD.GATE_CD AND PODT.BUYER_CD = POHD.BUYER_CD AND PODT.PO_NUM = POHD.PO_NUM AND PODT.DEL_FLAG = '0') LEFT JOIN (SELECT IVDT.GATE_CD , IVDT.BUYER_CD , IVDT.PO_NUM , IVDT.PO_SQ ,(SUM(IVDT.INV_QT), 0) AS INV_QT ,(SUM(IVDT.ITEM_AMT), 0) AS ITEM_AMT FROM STOCIVDT IVDT JOIN STOCIVHD IVHD ON (IVHD.GATE_CD = IVDT.GATE_CD AND IVHD.BUYER_CD = IVDT.BUYER_CD AND IVHD.INV_NUM = IVDT.INV_NUM AND IVHD.PROGRESS_CD IN ('100', '200') -- 작성중, 검수요청 AND IVHD.DEL_FLAG = '0') WHERE IVDT.GATE_CD = #{ses.gateCd} AND IVDT.DEL_FLAG = '0' GROUP BY IVDT.GATE_CD, IVDT.BUYER_CD, IVDT.PO_NUM, IVDT.PO_SQ) SUM_IVDT ON (SUM_IVDT.GATE_CD = PODT.GATE_CD AND SUM_IVDT.BUYER_CD = PODT.BUYER_CD AND SUM_IVDT.PO_NUM = PODT.PO_NUM AND SUM_IVDT.PO_SQ = PODT.PO_SQ) WHERE POHD.GATE_CD = #{ses.gateCd} AND POHD.BUYER_CD = #{BUYER_CD} AND POHD.PO_NUM PODT.PO_SQ IN
#{value.PO_NUM} #{value.PO_SQ}
AND POHD.DEL_FLAG = '0'

mapper.update:
UPDATE STOCPODT SET
      MOD_DATE    = SYSDATE
    , MOD_USER_ID = #{ses.userId}
    , INV_QT      = (INV_QT, 0) + (#{INV_QT}, 0) - (#{OLD_INV_QT}, 0)
    , PROGRESS_CD = CASE WHEN #{TYPE} = 'SEND' THEN #{PROGRESS_CD} ELSE PROGRESS_CD END
WHERE GATE_CD  = #{ses.gateCd}
  AND BUYER_CD = #{BUYER_CD}
  AND PO_NUM   = #{PO_NUM}
  AND PO_SQ    = #{PO_SQ}

UPDATE STOCPRDT SET
      MOD_DATE    = SYSDATE
    , MOD_USER_ID = #{ses.userId}
    , PROGRESS_CD = CASE WHEN #{TYPE} = 'SEND' THEN #{PROGRESS_CD} ELSE PROGRESS_CD END
WHERE GATE_CD  = #{ses.gateCd}
  AND (BUYER_CD, PR_NUM, PR_SQ) IN (
  			SELECT PB_BUYER_CD, PR_NUM, PR_SQ
  			  FROM STOCPODT
  			 WHERE GATE_CD  = #{ses.gateCd}
  			   AND BUYER_CD = #{BUYER_CD}
  			   AND PO_NUM   = #{PO_NUM}
  			   AND PO_SQ    = #{PO_SQ}
  	  )
  AND DEL_FLAG = '0'

mapper.insert:
        INSERT INTO STOCIVHD (
            GATE_CD
            , INV_NUM
            , REG_DATE
            , REG_USER_ID
            , MOD_DATE
            , MOD_USER_ID
            , DEL_FLAG
            , VENDOR_CD
            , BUYER_CD
            , CUR
            , INV_AMT
            , PURCHASE_TYPE
            , DEPT_CD
            , SUPPLY_AMT
            , VAT_AMT
            , VAT_TYPE
            , PROGRESS_CD
            , DELIVERY_TYPE
            )
        VALUES (
            #{ses.gateCd}
            , #{INV_NUM}
            , SYSDATE
            , #{ses.userId}
            , SYSDATE
            , #{ses.userId}
            , '0'
            , #{ses.companyCd}
            , #{BUYER_CD}
            , #{CUR}
            ,(#{INV_AMT}, 0)
            , #{PURCHASE_TYPE}
            , #{DEPT_CD}
            ,(#{INV_AMT}, 0) - (#{VAT_AMT}, 0)
            ,(#{VAT_AMT}, 0)
            , #{VAT_TYPE}
            , #{PROGRESS_CD}
            , #{DELIVERY_TYPE}
		)

mapper.update:
UPDATE STOCIVHD SET
      MOD_DATE    = SYSDATE
    , MOD_USER_ID = #{ses.userId}
    , INV_AMT     = (INV_AMT, 0) + (#{INV_AMT}, 0) - (#{OLD_INV_AMT}, 0)
    , VAT_AMT     = (VAT_AMT, 0) + (#{VAT_AMT}, 0) - (#{OLD_VAT_AMT}, 0)
    , SUPPLY_AMT  = (SUPPLY_AMT, 0) + ((#{INV_AMT}, 0) - (#{VAT_AMT}, 0)) - ((#{OLD_INV_AMT}, 0) - (#{OLD_VAT_AMT}, 0))
    , PROGRESS_CD = #{PROGRESS_CD}
WHERE GATE_CD  = #{ses.gateCd}
  AND BUYER_CD = #{BUYER_CD}
  AND INV_NUM  = #{INV_NUM}

UPDATE STOCIVHD SET
      SIGN_VALUE  = #{SIGN_VALUE}
    , SIGN_RANDOM = #{SIGN_RANDOM}
    , MOD_DATE    = SYSDATE
    , MOD_USER_ID = #{ses.userId}
WHERE GATE_CD  = #{ses.gateCd}
  AND BUYER_CD = #{BUYER_CD}
  AND INV_NUM  = #{INV_NUM}

