    , #{ses.userId}
    , SYSDATE
    , #{ses.userId}
    , '0'
    , #{ATT_FILE_NUM}
    , #{PO_NUM}
    , '1'
    , #{PURCHASE_TYPE}
    ,#{PIC_USER_NM}
    ,#{PIC_TEL_NUM}
    ,#{PIC_CELL_NUM}
    , #{ses.companyCd}
    , #{RMK_TEXT_NUM}
    , CASE WHEN #{TYPE} = 'SEND' THEN SYSDATE ELSE NULL END
    , #{INV_DATE}
    , #{BUYER_CD}
)

mapper.update:
UPDATE STOCIVGH SET
      ATT_FILE_NUM    = #{ATT_FILE_NUM}
    , RMK_TEXT_NUM    = #{RMK_TEXT_NUM}
    , SEND_DATE       = CASE WHEN #{TYPE} = 'SEND' THEN SYSDATE ELSE NULL END
    , INV_SEND_DATE   = #{INV_DATE}
    , VENDOR_USER_NM  = #{PIC_USER_NM}
    , VENDOR_TEL_NUM  = #{PIC_TEL_NUM}
    , VENDOR_CELL_NUM = #{PIC_CELL_NUM}
    , MOD_DATE        = SYSDATE
    , MOD_USER_ID     = #{ses.userId}
WHERE GATE_CD  = #{ses.gateCd}
  AND BUYER_CD = #{BUYER_CD}
  AND INV_NUM  = #{INV_NUM}

mapper.insert:
        INSERT INTO STOCIVDT (
            GATE_CD
            , INV_NUM
            , INV_SQ
            , REG_DATE
            , REG_USER_ID
            , MOD_DATE
            , MOD_USER_ID
            , DEL_FLAG
            , PO_NUM
            , PO_SQ
            , ITEM_CD
            , ITEM_DESC
            , ITEM_SPEC
            , UNIT_CD
            , INV_QT
            , UNIT_PRC
            , ITEM_AMT
            , PAY_CNT
            , ITEM_RMK
            , PURCHASE_TYPE
            , MAKER_CD
            , MAKER_PART_NO
            , SUPPLY_AMT
            , VAT_AMT
            , BUYER_CD
            , DEPT_CD
            , PR_BUYER_CD
            , PR_DEPT_CD
		)
        VALUES (
            #{ses.gateCd}
            , #{INV_NUM}
            ,(SELECT (MAX(INV_SQ), 0) + 1
                FROM STOCIVDT
               WHERE GATE_CD = #{ses.gateCd}
                 AND INV_NUM = #{INV_NUM})
            , SYSDATE
            , #{ses.userId}
            , SYSDATE
            , #{ses.userId}
            , '0'
            , #{PO_NUM}
            , #{PO_SQ}
            , #{ITEM_CD}
            , #{ITEM_DESC}
            , #{ITEM_SPEC}
            , #{UNIT_CD}
            ,(#{INV_QT}, 0)
            ,(#{UNIT_PRC}, 0)
            ,(#{ITEM_AMT}, 0)
            , '1'
            , #{ITEM_RMK}
            , #{PURCHASE_TYPE}
            , #{MAKER_CD}
            , #{MAKER_PART_NO}
            ,(#{ITEM_AMT}, 0) - (#{VAT_AMT}, 0)
            ,(#{VAT_AMT}, 0)
            , #{BUYER_CD}
            , #{DEPT_CD}
            , #{PR_BUYER_CD}
            , #{PR_DEPT_CD}
		)

